import { useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import {
  Star,
  Grid,
  List as ListIcon,
  Search as SearchIcon,
  LayoutDashboard,
  FolderKanban,
  Clock,
  BarChart3,
  Briefcase,
  Settings,
  Users,
  DollarSign,
  TrendingUp,
  FileText,
  Activity,
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import ScrollContainer from '@/components/layout/ScrollContainer';

interface MenuItem {
  title: string;
  description: string;
  icon: React.ComponentType<{ className?: string }>;
  path: string;
  category: string;
  badge?: string;
}

const menuItems: MenuItem[] = [
  // Dashboard
  {
    title: 'Dashboard',
    description: 'View project overview and key metrics',
    icon: LayoutDashboard,
    path: '/dashboard',
    category: 'Main',
  },

  // Projects
  {
    title: 'All Projects',
    description: 'View and manage all projects',
    icon: FolderKanban,
    path: '/projects',
    category: 'Projects',
  },
  {
    title: 'Create Project',
    description: 'Start a new project',
    icon: FolderKanban,
    path: '/projects/create',
    category: 'Projects',
    badge: 'New',
  },
  {
    title: 'My Projects',
    description: 'View your assigned projects',
    icon: Briefcase,
    path: '/projects/my-projects',
    category: 'Projects',
  },
  {
    title: 'Project Table',
    description: 'View projects in table format',
    icon: FileText,
    path: '/projects/table',
    category: 'Projects',
  },

  // Time & Expenses
  {
    title: 'Timesheet',
    description: 'Log and track work hours',
    icon: Clock,
    path: '/timesheet',
    category: 'Time & Expenses',
  },
  {
    title: 'Expenses',
    description: 'Track and manage project expenses',
    icon: DollarSign,
    path: '/expenses',
    category: 'Time & Expenses',
  },
  {
    title: 'Cost Management',
    description: 'Monitor project budgets and costs',
    icon: TrendingUp,
    path: '/cost-management',
    category: 'Time & Expenses',
  },

  // Resources
  {
    title: 'Resource Management',
    description: 'Manage team capacity and allocation',
    icon: Users,
    path: '/resources',
    category: 'Resources',
  },
  {
    title: 'Team Members',
    description: 'View and manage team members',
    icon: Users,
    path: '/resources/team',
    category: 'Resources',
  },
  {
    title: 'Allocation',
    description: 'Allocate resources to projects',
    icon: Users,
    path: '/resources/allocation',
    category: 'Resources',
  },

  // Analytics
  {
    title: 'Reports',
    description: 'Generate and view reports',
    icon: BarChart3,
    path: '/reports',
    category: 'Analytics',
  },
  {
    title: 'Analytics',
    description: 'View detailed analytics and insights',
    icon: TrendingUp,
    path: '/analytics',
    category: 'Analytics',
  },

  // Organization
  {
    title: 'Activity Log',
    description: 'Track system activities and changes',
    icon: Activity,
    path: '/activity',
    category: 'Organization',
  },
  {
    title: 'Search',
    description: 'Search across all items',
    icon: SearchIcon,
    path: '/search',
    category: 'Organization',
  },

  // Settings
  {
    title: 'Settings',
    description: 'Manage your preferences and profile',
    icon: Settings,
    path: '/settings',
    category: 'Settings',
  },
];

const categories = ['Main', 'Projects', 'Time & Expenses', 'Resources', 'Analytics', 'Organization', 'Settings'];

export default function Menu() {
  const navigate = useNavigate();
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [selectedCategory, setSelectedCategory] = useState<string>('all');
  const [searchQuery, setSearchQuery] = useState('');
  const [favorites, setFavorites] = useState<Set<string>>(new Set());

  const filteredItems = menuItems.filter(item => {
    const matchesCategory = selectedCategory === 'all' || item.category === selectedCategory;
    const matchesSearch = item.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
      item.description.toLowerCase().includes(searchQuery.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  const handleAddFavorite = (item: MenuItem) => {
    const newFavorites = new Set(favorites);
    if (newFavorites.has(item.path)) {
      newFavorites.delete(item.path);
    } else {
      newFavorites.add(item.path);
    }
    setFavorites(newFavorites);
    localStorage.setItem('menuFavorites', JSON.stringify(Array.from(newFavorites)));
  };

  const handleNavigate = (path: string) => {
    navigate(path);
  };

  return (
    <ScrollContainer>
      <div className="space-y-6 p-4">
        {/* Header */}
        <div>
          <h1 className="text-3xl font-bold text-gray-900">Menu</h1>
          <p className="text-gray-600 mt-1">Access all features and sections</p>
        </div>

        {/* Search & View Controls */}
        <Card>
          <CardContent className="p-4">
            <div className="space-y-4">
              <div className="relative">
                <SearchIcon className="absolute left-3 top-1/2 transform -translate-y-1/2 h-5 w-5 text-gray-400" />
                <input
                  type="text"
                  placeholder="Search menu items..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                />
              </div>

              <div className="flex items-center justify-between">
                <div className="flex gap-2 flex-wrap">
                  <Button
                    variant={selectedCategory === 'all' ? 'default' : 'outline'}
                    size="sm"
                    onClick={() => setSelectedCategory('all')}
                  >
                    All
                  </Button>
                  {categories.map(category => (
                    <Button
                      key={category}
                      variant={selectedCategory === category ? 'default' : 'outline'}
                      size="sm"
                      onClick={() => setSelectedCategory(category)}
                    >
                      {category}
                    </Button>
                  ))}
                </div>

                <div className="flex gap-2">
                  <Button
                    variant={viewMode === 'grid' ? 'default' : 'outline'}
                    size="icon"
                    onClick={() => setViewMode('grid')}
                  >
                    <Grid className="h-4 w-4" />
                  </Button>
                  <Button
                    variant={viewMode === 'list' ? 'default' : 'outline'}
                    size="icon"
                    onClick={() => setViewMode('list')}
                  >
                    <ListIcon className="h-4 w-4" />
                  </Button>
                </div>
              </div>
            </div>
          </CardContent>
        </Card>

        {/* Menu Items */}
        {viewMode === 'grid' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {filteredItems.map(item => {
              const Icon = item.icon;
              const isFavorite = favorites.has(item.path);
              return (
                <Card
                  key={item.path}
                  className="cursor-pointer hover:shadow-lg transition-all"
                  onClick={() => handleNavigate(item.path)}
                >
                  <CardContent className="p-6">
                    <div className="flex items-start justify-between mb-3">
                      <div className="h-12 w-12 rounded-lg bg-blue-100 flex items-center justify-center">
                        <Icon className="h-6 w-6 text-blue-600" />
                      </div>
                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          handleAddFavorite(item);
                        }}
                        className="p-2 hover:bg-gray-100 rounded-lg transition-colors"
                      >
                        <Star
                          className={`h-5 w-5 ${
                            isFavorite ? 'fill-yellow-400 text-yellow-400' : 'text-gray-400'
                          }`}
                        />
                      </button>
                    </div>

                    <h3 className="font-semibold text-gray-900 mb-1 flex items-center gap-2">
                      {item.title}
                      {item.badge && (
                        <Badge className="bg-blue-100 text-blue-800 text-xs">
                          {item.badge}
                        </Badge>
                      )}
                    </h3>

                    <p className="text-sm text-gray-600 mb-3">{item.description}</p>

                    <Badge variant="outline">{item.category}</Badge>
                  </CardContent>
                </Card>
              );
            })}
          </div>
        ) : (
          <Card>
            <CardContent className="p-0">
              <div className="divide-y divide-gray-200">
                {filteredItems.map(item => {
                  const Icon = item.icon;
                  const isFavorite = favorites.has(item.path);
                  return (
                    <div
                      key={item.path}
                      onClick={() => handleNavigate(item.path)}
                      className="p-4 hover:bg-gray-50 cursor-pointer transition-colors flex items-center justify-between"
                    >
                      <div className="flex items-center gap-4 flex-1">
                        <Icon className="h-5 w-5 text-blue-600" />
                        <div>
                          <h3 className="font-medium text-gray-900 flex items-center gap-2">
                            {item.title}
                            {item.badge && (
                              <Badge className="bg-blue-100 text-blue-800 text-xs">
                                {item.badge}
                              </Badge>
                            )}
                          </h3>
                          <p className="text-sm text-gray-600">{item.description}</p>
                        </div>
                      </div>

                      <div className="flex items-center gap-3 flex-shrink-0">
                        <Badge variant="outline">{item.category}</Badge>
                        <button
                          onClick={(e) => {
                            e.stopPropagation();
                            handleAddFavorite(item);
                          }}
                          className="p-2 hover:bg-gray-200 rounded-lg transition-colors"
                        >
                          <Star
                            className={`h-5 w-5 ${
                              isFavorite ? 'fill-yellow-400 text-yellow-400' : 'text-gray-400'
                            }`}
                          />
                        </button>
                      </div>
                    </div>
                  );
                })}
              </div>
            </CardContent>
          </Card>
        )}

        {filteredItems.length === 0 && (
          <Card className="p-8 text-center">
            <SearchIcon className="h-12 w-12 mx-auto mb-4 text-gray-400" />
            <h3 className="text-lg font-medium text-gray-900 mb-2">No items found</h3>
            <p className="text-gray-600">Try adjusting your search or category filter</p>
          </Card>
        )}
      </div>
    </ScrollContainer>
  );
}
